export class NameIndex {
  private index: Map<string, Entity> = new Map();
  build(entities: Entity[]): void { ... }
  get(name: string): Entity | undefined { return this.index.get(name); }
  add(entity: Entity): void { this.index.set(entity.name, entity); }
  remove(name: string): void { this.index.delete(name); }
}

export class GraphStorage {
